<template>
  <el-container style="height:100%">
    <el-main>
      <el-table :data="tableData" style="width:100%;height:100%;">
        <el-table-column prop="devid" label="id" width="40"></el-table-column>
        <el-table-column prop="devname" label="name" width="80"></el-table-column>
        <el-table-column prop="devtype" label="name" width="80"></el-table-column>
        <el-table-column prop="timestamp" label="timestamp" width="180"></el-table-column>
        <el-table-column prop="pos" label="pos" width="180"></el-table-column>
        <el-table-column prop="speed" label="speed"></el-table-column>
        <el-table-column prop="current" label="current"></el-table-column>
        <el-table-column prop="temperature" label="temperature"></el-table-column>
        <el-table-column prop="" label="">
          <template slot-scope="scope">
            <el-button @click="onClickHistory(scope.row)" type="text" size="small">History</el-button>
            <el-button @click="onClickUpdate(scope.row)" type="text" size="small">Update</el-button>
          </template>
        </el-table-column>
      </el-table>
    </el-main>
    <el-footer height="300px" >
      <div id="chart-motor-status" style="height:100%;width:100%;"></div>
    </el-footer>
  </el-container>
</template>

<script>
import proto from "../assets/sdkapi_pb.js"
export default {
  name: 'MotorStatus',
  props: {
    msg: String
  },
  data() {
    this.chart = null;
    return {
      tableData: [{
        devid: '-',
        devname: '-',
        devtype: '-',
        timestamp: '-',
        pos: '-',
        speed: '-',
        current: '-',
        temperature: '-',
      }]
    };
  },
  mounted() {
    var that = this;
    this.chart = this.$echarts.init(document.getElementById("chart-motor-status"));
    this.$bus.$on("websocket-data-received", function(d) {
      var data = d.data;
      if (data.command == proto.Command.CMD_STATUS_DATA_UPDATE) {
        that.updateTable(data);
      } else if (data.command == proto.Command.CMD_GET_HISTORY_DATA) {
        that.updateChart(data);
      } else if (data.command == proto.Command.CMD_GET_STATUS_DATA) {
        that.updateTableData(data);
      } else if (data.command == proto.Command.CMD_GET_DATA_LIST) {
        that.updateDataList(data);
      }
    });
  },
  methods: {
    handleSelect(key, keyPath) {
      console.log(key, keyPath);
    },
    onClickHistory(row) {
      var request = new proto.Request();
      request.setCommand(proto.Command.CMD_GET_HISTORY_DATA);
      var param_data = request.addParamData();
      param_data.setKey("data_type");
      param_data.setVal(row.devtype);
      param_data = request.addParamData();
      param_data.setKey("devid");
      param_data.setVal(row.devid + "");
      var d = request.serializeBinary();                  // 序列化
      console.log("request history: id: " + row.did);
      this.$bus.$emit("websocket-send-data", {data:d});
    },
    onClickUpdate(row) {
      var request = new proto.Request();
      request.setCommand(proto.Command.CMD_GET_STATUS_DATA);
      var param_data = request.addParamData();
      param_data.setKey("data_type");
      param_data.setVal(row.devtype);
      param_data = request.addParamData();
      param_data.setKey("devid");
      param_data.setVal(row.devid + "");
      var d = request.serializeBinary();                  // 序列化
      console.log("request history: id: " + row.did);
      this.$bus.$emit("websocket-send-data", {data:d});
    },
    updateDataList(d) {
      console.log("update data list: ", d);
      if (!d || !d.dataList || !d.dataList.dataItemList) {
        console.error("updata data list error: ", d);
      }
      var tableData = [];
      d.dataList.dataItemList.forEach(v => {
        if (v.devtype != "motor") return;
        var data = {};
        data.devid = v.devid;
        data.devname = v.devname;
        data.devtype = v.devtype;
        data.timestamp = '-';
        data.pos = '-';
        data.speed = '-';
        data.current = '-';
        data.temperature = '-';
        tableData.push(data);
      });
      tableData.sort(function(a, b) {
        return a.devid - b.devid;
      });
      this.tableData = tableData;
    },
    updateTableData(d) {
      console.log("update table data: ", d);
      if (!d || !d.statusData || !d.statusData.motorDataList) {
        console.error("updata table data error: ", d);
      }
      d.statusData.motorDataList.forEach(v => {
        var devid = v.devid;
        this.tableData.forEach(vv => {
          if (parseInt(vv.devid) !== parseInt(devid)) return;
          console.log(vv.devid, devid);
          this.$nextTick(function() {
          vv.current = Math.trunc(v.current * 1000) / 1000;
          vv.pos = Math.trunc(v.pos * 1000) / 1000;
          vv.speed = Math.trunc(v.speed * 1000) / 1000;
          vv.temperature = Math.trunc(v.temperature * 1000) / 1000;
          vv.timestamp = Math.trunc(v.timestamp) / 1000;
          });
        });
      });
    },
    updateChart(d) {
      if (!d || !d.statusData || !d.statusData.motorDataList) {
        console.error("updata char error: ", d);
      }

      var xAxis = [];
      var yAxis1 = [];
      var yAxis2 = [];
      var yAxis3 = [];
      d.statusData.motorDataList.forEach((v) => {
        xAxis.push(v.timestamp / 1000);
        yAxis1.push([v.timestamp / 1000, v.pos]);
        yAxis2.push([v.timestamp / 1000, v.speed]);
        yAxis3.push([v.timestamp / 1000, v.temprature]);
      });

      var option = {
        grid: {
          left: 30,
          top: 30,
          right: 30,
          bottom: 30,
        },
        xAxis: {
          type: "value",
          min: xAxis[0],
          max: xAxis[xAxis.length - 1],
        },
        yAxis: {
          type: "value",
        },
        series: [
          {
            data: yAxis1,
            type: "line",
            smooth: true,
            lineStyle: { width: 1 },
          },
          {
            data: yAxis2,
            type: "line",
            smooth: true,
            lineStyle: { width: 1 },
          },
          {
            data: yAxis3,
            type: "line",
            smooth: true,
            lineStyle: { width: 1 },
          }
        ],
      };
      this.chart.setOption(option);
    }
  }
}
</script>

