<template>
  <el-container style="height:100%">
    <el-main>
      <el-row :gutter="0">
      <el-col :span="14">
      <el-form ref="form" :model="form" label-width="60px" style="height:160px">
        <el-form-item label="指令">
          <el-select v-model="commandSelect" placeholder="请选择" style="width:98%;display:block">
            <el-option v-for="item in commandList" :key="item.value" :label="item.label" :value="item.value" style="display:block"></el-option>
          </el-select>
        </el-form-item>
        <el-form-item label="参数" style="text-align:left">
          <div style="display:inline-block">devtype:&nbsp;&nbsp;</div>
          <div style="display:inline-block">
            <el-select v-model="devTypeSelect" placeholder="请选择" style="width:98%;" @change="onDevTypeChange">
              <el-option v-for="item in devList" :key="item.value" :label="item.value + '(' + item.data.length + ')'" :value="item.value" style="display:block"></el-option>
            </el-select>
          </div>

          <div style="display:inline-block">devid:&nbsp;&nbsp;</div>
          <div style="display:inline-block">
            <el-select v-model="devSelect" placeholder="请选择" style="width:80%;display:block" @change="onDevSelectChange">
              <el-option v-for="item in devSelectList" :key="item.devid" :label="item.devname + '(' + item.devid + ')'" :value="item.devid" style="display:block"></el-option>
            </el-select>
          </div>

          <el-button type="primary" @click="onSubmit">确定</el-button>
        </el-form-item>
      </el-form>

      <el-table :data="tableData" style="width:100%;height:100%;">
        <el-table-column prop="index" label="ID" width="40"></el-table-column>
        <el-table-column prop="startTimeStr" label="请求时间" width="190"></el-table-column>
        <el-table-column prop="endTimeStr" label="响应时间" width="190"></el-table-column>
        <el-table-column prop="costTime" label="时间差" width="80"></el-table-column>
        <el-table-column prop="responseDataSize" label="数据大小"></el-table-column>
        <el-table-column prop="" label="">
          <template slot-scope="scope">
            <el-button @click="onClickDetail(scope.row)" type="text" size="small">Detail</el-button>
          </template>
        </el-table-column>
      </el-table>

      </el-col>

      <el-col :span="10" style="height:100%;">
        <div style="width:98%;height:100%;border:1px solid gray;margin:0px 0px;text-align:left">
          <pre>{{textarea}}</pre>
        </div>
      </el-col>

      </el-row>
    </el-main>
    <el-footer height="0px"></el-footer>
  </el-container>
</template>

<script>
import proto from "../assets/sdkapi_pb.js"
export default {
  name: 'DebugPage',
  props: {
    msg: String
  },
  data() {
    this.request_sequence = 0;
    this.dayjs = require("dayjs");
    return {
      commandSelect: "",
      devTypeSelect: "",
      devSelect: "",
      devSelectList: "",
      devList: [
        { value: "camera", data: [], label: "" },
        { value: "radar", data: [],  label: "" },
        { value: "imu", data: [],  label: "" },
        { value: "switch", data: [],  label: "" },
        { value: "motor", data: [],  label: "" },
        { value: "power", data: [],  label: "" },
        { value: "cpu", data: [],  label: "" },
        { value: "mem", data: [],  label: "" },
        { value: "disk", data: [],  label: "" },
        { value: "chassis", data: [],  label: "" },
        { value: "remote_control", data: [],  label: "" },
        { value: "audio", data: [],  label: "" },
      ],
      commandList: [
        { value: proto.Command.CMD_SET_PARAMETER, label: "设置参数(CMD_SET_PARAMETER)" },
        { value: proto.Command.CMD_GET_DATA_LIST, label: "获取数据列表(CMD_GET_DATA_LIST)" },
        { value: proto.Command.CMD_GET_HISTORY_DATA, label: "获取历史数据(CMD_GET_HISTORY_DATA)" },
        { value: proto.Command.CMD_GET_STATUS_DATA, label: "获取状态数据(CMD_GET_STATUS_DATA)" },
        { value: proto.Command.CMD_GET_LOG_DATA, label: "获取日志(CMD_GET_LOG_DATA)" },
        { value: proto.Command.CMD_GET_TOPIC_DATA, label: "获取Topic数据(CMD_GET_TOPIC_DATA)" },
        { value: proto.Command.CMD_SET_TOPIC_DATA, label: "获取Topic数据(CMD_SET_TOPIC_DATA)" },
        { value: proto.Command.CMD_RUN_STATUS, label: "执行状态(CMD_RUN_STATUS)" },
        { value: proto.Command.CMD_RUN_ACTION, label: "执行动作(CMD_RUN_ACTION)" },
        { value: proto.Command.CMD_RUN_DIAGNOSIS, label: "执行诊断(CMD_RUN_DIAGNOSIS)" },
        { value: proto.Command.CMD_RUN_VERSION_UPDATE, label: "执行版本升级(CMD_RUN_VERSION_UPDATE)" },
        { value: proto.Command.CMD_RUN_CALL_SERVICE, label: "执行服务调用(CMD_RUN_CALL_SERVICE)" },
      ],
      form: {
        command: '',
      },
      textarea: "",
      tableData: [],
    };
  },
  mounted() {
    var that = this;
    this.$bus.$on("websocket-data-received", function(d) {
      var data = d.data;
      if (data.command == proto.Command.CMD_STATUS_DATA_UPDATE) {
        that.updateTable(data, d.size);
      } else if (data.command == proto.Command.CMD_GET_HISTORY_DATA) {
        that.updateChart(data);
      } else if (data.command == proto.Command.CMD_GET_DATA_LIST) {
        that.updateDataList(data);
      } else {
        that.updateTableData(data, d.size);
      }
    });
  },
  methods: {
    handleSelect(key, keyPath) {
      console.log(key, keyPath);
    },
    onClickHistory(row) {
      var request = new proto.Request();
      request.setCommand(proto.Command.CMD_GET_HISTORY_DATA);
      var param_data = request.addParamData();
      param_data.setKey("data_type");
      param_data.setVal(row.devtype);
      param_data = request.addParamData();
      param_data.setKey("devid");
      param_data.setVal(row.devid + "");
      var d = request.serializeBinary();                  // 序列化
      console.log("request history: id: " + row.did);
      this.$bus.$emit("websocket-send-data", {data:d});
    },
    onClickUpdate(row) {
      var request = new proto.Request();
      request.setCommand(proto.Command.CMD_GET_STATUS_DATA);
      var param_data = request.addParamData();
      param_data.setKey("data_type");
      param_data.setVal(row.devtype);
      param_data = request.addParamData();
      param_data.setKey("devid");
      param_data.setVal(row.devid + "");
      var d = request.serializeBinary();                  // 序列化
      console.log("request history: id: " + row.did);
      this.$bus.$emit("websocket-send-data", {data:d});
    },
    onDevTypeChange(d) {
      for (var i = 0; i < this.devList.length; i++) {
        if (this.devList[i].value == d) {
          this.devSelectList = this.devList[i].data;
          break;
        }
      }
      console.log(d, this.devSelectList);
    },
    onDevSelectChange(d) {
      console.log(d);
    },
    onClickDetail(d) {
      this.textarea = d.responseData;
    },
    onSubmit() {
      console.log("submit: command: " + this.commandSelect + ", devtype: " + this.devTypeSelect + ", dev: " + this.devSelect);

      var header = new proto.Header();
      header.setUserdata("debugger");
      header.setRequestSequence(this.request_sequence);
      var request = new proto.Request();
      request.setCommand(this.commandSelect);
      header = request.setHeader(header);
      var param_data = request.addParamData();
      param_data.setKey("data_type");
      param_data.setVal(this.devTypeSelect);
      param_data = request.addParamData();
      param_data.setKey("devid");
      param_data.setVal(this.devSelect + "");
      var d = request.serializeBinary();
      this.$bus.$emit("websocket-send-data", {data:d});

      var dd = {
        index: this.tableData.length + 1,
        request_sequence: this.request_sequence,
        startTime: Date.now(),
        startTimeStr: '',
        endTime: '',
        endTimeStr: '',
        responseData: null,
      };
      this.tableData.push(dd);
      this.request_sequence++;
    },
    updateDataList(d) {
      console.log("update data list: ", d);
      if (!d || !d.dataList || !d.dataList.dataItemList) {
        console.error("updata data list error: ", d);
      }
      d.dataList.dataItemList.forEach(v => {
        var devtype = v.devtype;
        for (var i = 0; i < this.devList.length; i++) {
          if (this.devList[i].value == devtype) {
            this.devList[i].data.push(v);
          }
        }
      });
      this.devList.sort(function(a, b) {
        return b.data.length - a.data.length;
      });
      this.devList.forEach(v => {
        v.data.sort(function(a, b) { return a.devid - b.devid; });
      });
    },
    updateTableData(d, size) {
      if (!d || !d.header || d.header.userdata !== 'debugger') {
        return;
      }
      for (var i = 0; i < this.tableData.length; ++i) {
        if (this.tableData[i].request_sequence === d.header.requestSequence) {
          var dd = this.tableData[i];
          this.tableData[i].responseData = d;
          this.tableData[i].endTime = Date.now();
          this.tableData[i].costTime = Math.trunc(this.tableData[i].endTime - this.tableData[i].startTime) / 1000;
          var t1 = this.dayjs(dd.startTime);
          dd.startTimeStr = t1.format("YYYY-MM-DD HH:mm:ss") + "." + t1.millisecond();
          var t2 =  this.dayjs(dd.endTime);
          dd.endTimeStr = t2.format("YYYY-MM-DD HH:mm:ss") + "." + t2.millisecond();
          this.tableData[i].responseDataSize = size;
          console.log("data size: " + size);
          this.textarea = dd.responseData;
          break;
        }
      }
    },
    updateChart(d) {
    }
  }
}
</script>

